def load_hover_raw(fname:str, vocab:Optional[Dict]=None):
    raw_data = load_json(fname)

    qry_ids, qry_txt = [], []
    vocab = {} if vocab is None else vocab
    
    data, indices, indptr = [], [], [0]
    
    for o in tqdm(raw_data):
        qry_ids.append(o["uid"])
        qry_txt.append(o["claim"])
    
        labels = set([f[0] for f in o["supporting_facts"]])
        
        for lbl in labels:
            assert lbl in vocab, f"`{lbl}` not present in the corpus."

            idx = vocab[lbl]
            data.append(1.0)
            indices.append(idx)
                
        indptr.append(len(indices))
        
    matrix = sp.csr_matrix((data, indices, indptr), shape=(len(indptr) - 1, len(vocab)))
    return qry_ids, qry_txt, matrix


def process_hover(data_dir:str, lbl_file:str, save_dir:str):
    lbls = load_jsonl(lbl_file)
    vocab = {o["title"]:i for i,o in enumerate(lbls)}

    trn_ids, trn_txt, trn_lbl = load_hover_raw(f"{data_dir}/hover_train_release_v1.1.json", vocab=vocab)
    tst_ids, tst_txt, tst_lbl = load_hover_raw(f"{data_dir}/hover_dev_release_v1.1.json", vocab=vocab)

    os.makedirs(f"{save_dir}/raw_data", exist_ok=True)

    save_raw_file(f"{save_dir}/raw_data/train.raw.csv", trn_ids, trn_txt)
    sp.save_npz(f"{save_dir}/trn_X_Y.npz", trn_lbl)

    save_raw_file(f"{save_dir}/raw_data/test.raw.csv", tst_ids, tst_txt)
    sp.save_npz(f"{save_dir}/tst_X_Y.npz", tst_lbl)

    lbl_txt = [o["title"] + " [SEP] " + o["text"] for o in lbls]
    lbl_ids = list(range(len(lbl_txt)))
    save_raw_file(f"{save_dir}/raw_data/label.raw.csv", lbl_ids, lbl_txt)

    return (trn_ids, trn_txt, trn_lbl), (tst_ids, tst_txt, tst_lbl), (lbl_ids, lbl_txt)


def load_exfever_raw(fname:str, start_qry_id:Optional[int]=0, vocab:Optional[Dict]=None):
    df = pd.read_csv(fname)

    qry_ids, qry_txt = [], []
    vocab = {} if vocab is None else vocab
    
    data, indices, indptr = [], [], [0]
    
    for i in tqdm(range(df.shape[0])):
        qry_ids.append(i + start_qry_id)
        qry_txt.append(df.iloc[i]["claim"])
    
        labels = set(ast.literal_eval(df.iloc[i]["golden entity"]))
        
        for lbl in labels:
            if lbl not in vocab: continue

            idx = vocab[lbl]
            data.append(1.0)
            indices.append(idx)
                
        indptr.append(len(indices))
        
    matrix = sp.csr_matrix((data, indices, indptr), shape=(len(indptr) - 1, len(vocab)))
    return qry_ids, qry_txt, matrix


def process_exfever(data_dir:str, lbl_file:str, save_dir:str):
    lbls = load_jsonl(lbl_file)
    vocab = {o["_id"]:i for i,o in enumerate(lbls)}

    trn_ids, trn_txt, trn_lbl = load_exfever_raw(f"{data_dir}/EX-FEVER/data/train.csv", vocab=vocab)

    start_qry_id = len(trn_ids)
    dev_ids, dev_txt, dev_lbl = load_exfever_raw(f"{data_dir}/EX-FEVER/data/dev.csv", start_qry_id=start_qry_id, vocab=vocab)

    start_qry_id += len(dev_ids)
    tst_ids, tst_txt, tst_lbl = load_exfever_raw(f"{data_dir}/EX-FEVER/data/test.csv", start_qry_id=start_qry_id, vocab=vocab)

    os.makedirs(f"{save_dir}/raw_data", exist_ok=True)

    save_raw_file(f"{save_dir}/raw_data/train.raw.csv", trn_ids, trn_txt)
    sp.save_npz(f"{save_dir}/trn_X_Y.npz", trn_lbl)

    save_raw_file(f"{save_dir}/raw_data/dev.raw.csv", dev_ids, dev_txt)
    sp.save_npz(f"{save_dir}/dev_X_Y.npz", dev_lbl)

    save_raw_file(f"{save_dir}/raw_data/test.raw.csv", tst_ids, tst_txt)
    sp.save_npz(f"{save_dir}/tst_X_Y.npz", tst_lbl)

    lbl_txt = [o["title"] + " [SEP] " + o["text"] for o in lbls]
    lbl_ids = list(range(len(lbl_txt)))
    save_raw_file(f"{save_dir}/raw_data/label.raw.csv", lbl_ids, lbl_txt)

    return (trn_ids, trn_txt, trn_lbl), (tst_ids, tst_txt, tst_lbl), (lbl_ids, lbl_txt)


